11	// PodBuilder is a builder for v1.Pod objects to be used only in unit tests.
12	type PodBuilder struct {
13		pod *v1.Pod
14	}
15	
16	// NewPod returns a new PodBuilder to build v1.Pod objects. It is meant to be used only in unit tests.
17	func NewPod() *PodBuilder {
18		return &PodBuilder{
19			pod: &v1.Pod{},
20		}
21	}
22	
23	func (p *PodBuilder) WithName(name string) *PodBuilder {
24		p.pod.Name = name
25		return p
26	}
27	
28	func (p *PodBuilder) WithImagePullSecrets(imagePullSecrets ...string) *PodBuilder {
29		p.pod.Spec.ImagePullSecrets = make([]v1.LocalObjectReference, len(imagePullSecrets))
30		for i, secret := range imagePullSecrets {
31			p.pod.Spec.ImagePullSecrets[i] = v1.LocalObjectReference{
32				Name: secret,
33			}
34		}
35		return p
36	}
37	
38	func (p *PodBuilder) WithSchedulingGates(schedulingGates ...string) *PodBuilder {
39		p.pod.Spec.SchedulingGates = make([]v1.PodSchedulingGate, len(schedulingGates))
40		for i, gate := range schedulingGates {
41			p.pod.Spec.SchedulingGates[i] = v1.PodSchedulingGate{
42				Name: gate,
43			}
44		}
45		return p
46	}
47	
48	func (p *PodBuilder) WithContainersImages(images ...string) *PodBuilder {
49		for _, image := range images {
50			p.WithContainer(image, v1.PullIfNotPresent)
51		}
52		return p
53	}
54	
55	func (p *PodBuilder) WithContainerImagePullAlways(image string) *PodBuilder {
56		return p.WithContainer(image, v1.PullAlways)
57	}
58	
59	func (p *PodBuilder) WithContainer(image string, imagePullPolicy v1.PullPolicy) *PodBuilder {
60		// compute hash of the image name
61		hasher := fnv.New128()
62		hasher.Write([]byte(image))
63		name := hex.EncodeToString(hasher.Sum(nil))
64		if len(name) > 63 {
65			name = name[:63]
66		}
67		p.pod.Spec.Containers = append(p.pod.Spec.Containers, v1.Container{
68			Image:           image,
69			Name:            name,
70			ImagePullPolicy: imagePullPolicy,
71		})
72		return p
73	}
74	
75	func (p *PodBuilder) WithInitContainersImages(images ...string) *PodBuilder {
76		p.pod.Spec.InitContainers = make([]v1.Container, len(images))
77		for i, image := range images {
78			p.pod.Spec.InitContainers[i] = v1.Container{
79				Image: image,
80			}
81		}
82		return p
83	}
