85	// WithAffinity adds the affinity to the pod. If initialAffinity is not nil, it is used as the initial value
86	// of the pod's affinity. Otherwise, the pod's affinity is initialized to an empty affinity if it is nil.
87	func (p *PodBuilder) WithAffinity(initialAffinity *v1.Affinity) *PodBuilder {
88		if p.pod.Spec.Affinity == nil {
89			p.pod.Spec.Affinity = &v1.Affinity{}
90		}
91		if initialAffinity != nil {
92			p.pod.Spec.Affinity = initialAffinity
93		}
94		return p
95	}
96	
97	func (p *PodBuilder) WithNodeAffinity() *PodBuilder {
98		p.WithAffinity(nil)
99		if p.pod.Spec.Affinity.NodeAffinity == nil {
100			p.pod.Spec.Affinity.NodeAffinity = &v1.NodeAffinity{}
101		}
102		return p
103	}
104	
105	func (p *PodBuilder) WithRequiredDuringSchedulingIgnoredDuringExecution() *PodBuilder {
106		p.WithNodeAffinity()
107		if p.pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution == nil {
108			p.pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution = &v1.NodeSelector{}
109		}
110		return p
111	}
112	
113	func (p *PodBuilder) WithPreferredDuringSchedulingIgnoredDuringExecution(values ...*v1.PreferredSchedulingTerm) *PodBuilder {
114		p.WithNodeAffinity()
115		if p.pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution == nil {
116			p.pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution = []v1.PreferredSchedulingTerm{}
117		}
118		for i := range values {
119			if values[i] == nil {
120				panic("nil value passed to WithPreferredDuringSchedulingIgnoredDuringExecution")
121			}
122			p.pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution = append(
123				p.pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution, *values[i])
124		}
125		return p
126	}
127	
128	func (p *PodBuilder) WithNodeSelectorTermsMatchExpressions(
129		nodeSelectorTermsMatchExpressions ...[]v1.NodeSelectorRequirement) *PodBuilder {
130		p.WithRequiredDuringSchedulingIgnoredDuringExecution()
131		p.pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms = make(
132			[]v1.NodeSelectorTerm, len(nodeSelectorTermsMatchExpressions))
133		for i, matchExpressions := range nodeSelectorTermsMatchExpressions {
134			p.pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms[i] =
135				v1.NodeSelectorTerm{
136					MatchExpressions: matchExpressions,
137				}
138		}
139		return p
140	}
141	
142	func (p *PodBuilder) WithNodeSelectors(kv ...string) *PodBuilder {
143		if p.pod.Spec.NodeSelector == nil {
144			p.pod.Spec.NodeSelector = make(map[string]string)
145		}
146		if len(kv)%2 != 0 {
147			panic("the number of arguments must be even")
148		}
149		for i := 0; i < len(kv); i += 2 {
150			p.pod.Spec.NodeSelector[kv[i]] = kv[i+1]
151		}
152		return p
153	}
