155	func (p *PodBuilder) WithOwnerReferences(values ...*metav1.OwnerReference) *PodBuilder {
156		for i := range values {
157			if values[i] == nil {
158				panic("nil value passed to WithOwnerReferences")
159			}
160			p.pod.OwnerReferences = append(p.pod.OwnerReferences, *values[i])
161		}
162		return p
163	}
