180	func (p *PodBuilder) WithAnnotations(annotations map[string]string) *PodBuilder {
181		if p.pod.Annotations == nil {
182			p.pod.Annotations = make(map[string]string)
183		}
184		for key, value := range annotations {
185			p.pod.Annotations[key] = value
186		}
187		return p
188	}
189	
190	func (p *PodBuilder) WithLabels(labelsKeyValuesPair ...string) *PodBuilder {
191		if p.pod.Labels == nil {
192			p.pod.Labels = make(map[string]string)
193		}
194		if len(labelsKeyValuesPair)%2 != 0 {
195			// It's ok to panic as this is only used in unit tests.
196			panic("the number of arguments must be even")
197		}
198		for i := 0; i < len(labelsKeyValuesPair); i += 2 {
199			p.pod.Labels[labelsKeyValuesPair[i]] = labelsKeyValuesPair[i+1]
200		}
201		return p
202	}
203	
204	func (p *PodBuilder) WithOwnerReference(or metav1.OwnerReference) *PodBuilder {
205		p.pod.OwnerReferences = append(p.pod.OwnerReferences, or)
206		return p
207	}
208	
209	func (p *PodBuilder) WithContainerStatuses(statuses ...v1.ContainerStatus) *PodBuilder {
210		p.pod.Status.ContainerStatuses = statuses
211		return p
212	}
213	
214	func (p *PodBuilder) Build() *v1.Pod {
215		return p.pod
216	}
